var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"멈추어라, 불 <color=#ff3636>타오르는 어</color>린 양! 침몰<color=#ff3636> 당하는 부모</color>님을 위<b>하</b>여……!","JPN":"止まれ、燃<color=#ff3636>え上がる子</color>羊よ！　沈没<color=#ff3636>する両</color>親のた<b>め</b>に……！","ENG":"Stop, y<color=#ff3636>ou burnin</color>g young lamb! For <color=#ff3636>the sinking</color> par<b>ent</b>s...!","TWN":"止住吧，燃<color=#ff3636>燒的小</color>羊！為衰敗<color=#ff3636>的</color>父<b>母</b>親……！"},"stage":{"bg":"UNDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L5_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"다가<color=#ff3636>올 눈부신 멸</color>망을 위해, 괴상<color=#ff3636>망측한 용</color>서를 <b>빌</b> 지어다……!","JPN":"来る<color=#ff3636>べき輝かしい滅</color>亡のために、奇怪<color=#ff3636>な許</color>しを求<b>め</b>よ……！","ENG":"Pray f<color=#ff3636>or absurd</color> forgiveness, for t<color=#ff3636>he dazzling do</color>om to<b> come</b>......!","TWN":"燦<color=#ff3636>爛的末</color>日將到，祈求<color=#ff3636>詭異的</color>饒<b>恕</b> ……！"},"stage":{"bg":"UNDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_QM","text":{"KOREA":"휴우, 일단 이걸로 시간은 꽤 벌었을까나?","JPN":"ふう、これで一応時間がを稼げたかな？","ENG":"Phew... That should buy us some time, right?","TWN":"呼，這樣應該可以爭取些時間吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L11_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_QM","text":{"KOREA":"이쪽이야. 자매님. 빨리 안 오면 떼놓고 간다?","JPN":"こっちだよ、シスター。早く来ないと置いていくよ？","ENG":"This way. If you keep falling behind, I'll have to go without you, Sister.","TWN":"這裡！姊妹，你再不過來我要扔下你跑囉！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_QM","text":{"KOREA":"왜 그래? 자매님?","JPN":"どうしたの？　シスター。","ENG":"What's wrong? Sister?","TWN":"姊妹？你怎麼了？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저, 아그네스 자매님이라고 하셨죠? 구해 주셔서 감사합니다.","JPN":"あの、アグネスといいましたか？　助けていただきありがとうございます。","ENG":"S-sister Agnes, was it? Thank you for rescuing me.","TWN":"你說你是艾格妮絲姊妹對吧？謝謝你來救我。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그런데…… 그 옷차림은?","JPN":"でも……その服は？","ENG":"But... That uniform...","TWN":"不過……你這身打扮是？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"아아, 이거? 로마에 가면 로마 법을 따르라.","JPN":"ああ、これ？　郷に入っては郷に従えってね。","ENG":"Oh, this? \\"When in Rome\\", right?","TWN":"喔喔～這個喔？俗話說要入境隨俗的嘛。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"노출이 좀 많지만, 이 마을에 잠입하려면 얘들 복장 양식을 따라야 하거든.","JPN":"ちょっと露出が高いけど、この村に潜入するためには同じ服装でないとまずいから。","ENG":"It's a little revealing, but I had to adhere to their dress code in order to infiltrate the village.","TWN":"雖然有點暴露，不過要潛入這個村莊，就要先模仿他們的穿著嘛。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですか。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"어라? 우리 자매님, 표정이 왜 그럴까?","JPN":"あら？　なんだかうかない表情ね？","ENG":"Hmm? Why the long face, Sister?","TWN":"姊妹？你怎麼這個表情？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"대침식전이 아니라 대인작전을 요청했던 건 유감스럽게 됐어.","JPN":"対侵食戦じゃなくて、対人作戦を要請したのは残念だったわね。","ENG":"I'm sorry for requesting help as an anti-personnel operation, and not as an anti-C.O. one.","TWN":"我很遺憾，請求作戰的對象不是侵蝕體而是人。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"하지만 성황청의 지원이 올 동안 사태가 이렇게 갑자기 악화될 줄은 예상 못했거든.","JPN":"でも聖皇庁の支援が到着する前に、こんなに事態が悪化するとは思わなかったの。","ENG":"However, I didn't expect the situation to suddenly worsen while the Holy Curia's reinforcements were on their way.","TWN":"不過誰都沒想到，在聖皇廳之支援抵達前，情況會突然惡化成這樣。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"악화되었다고요?","JPN":"悪化した？","ENG":"Worsen?","TWN":"惡化？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"뭐, 이런 곳에선 흔해 빠진 얘기야.","JPN":"まあ、こういうところではよくあることだわ。","ENG":"Well, it's rather common around here.","TWN":"這種地方不是常有這種事嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"침식파 때문에 온건했던 자들까지 흉폭하게 변해버렸다는 이야기지.","JPN":"侵食波のせいで穏健な人まで凶暴になってしまったの。","ENG":"It's because Corruption ray transforms even the mildest ones into violent ones.","TWN":"因為侵蝕波的關係，原本好好的人突然發狠。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"그래도 너무 걱정하진 마, 자매님.","JPN":"でも、あまり心配しないでね。","ENG":"But don't sweat it, Sister.","TWN":"不過你別太擔心，"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"맡은 일의 뒤처리를 위해, 내가 몸소 자매님을 구해주러 왔잖아?","JPN":"任された仕事の後処理のために、私自ら助けに来たんだもの。","ENG":"I came to rescue you myself, right?","TWN":"為了收拾殘局，我這不是親自來救你了嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"자, 그럼 다시 가볼까?","JPN":"さて、それじゃ行きましょうか？","ENG":"Then, shall we get going?","TWN":"來，我們走吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"음?","JPN":"あら？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저…… 아그네스 자매님. 지금이라도 돌아가죠.","JPN":"あの……シスター・アグネス。今からでも戻りましょう。","ENG":"Uh... Sister Agnes. We should head back while we can.","TWN":"那個……艾格妮絲姊妹，你請回吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그곳에서 죽어가던 어린 양을 외면할 수 없어요.","JPN":"あそこで死にかけていた子羊を放っておくことはできません。","ENG":"I can't turn my back on a dying young lamb who needs our help back there.","TWN":"我無法放著在那裡瀕死的小羊不管。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"이상하네, 넬슨 자매님은 정말로 심의회 소속이야?","JPN":"変ね、シスター・ネルソンって本当に審議会所属なの？","ENG":"That's strange. Are you really a member of the Miracle Investigation Council, Sister Nelson?","TWN":"奇怪，尼爾森姊妹，你真的是議會的人嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"내가 아는 심의회 녀석들은 피도 눈물도 없는 비정한 족속들뿐이었는데.","JPN":"私の知ってる審議会のやつらは、みんな血も涙もない冷血漢なのに。","ENG":"The only members that I know are heartless and merciless.","TWN":"我認識的議會，全都是些沒血沒淚，六親不認的人。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"괜히 걔들이 주님의 미친개들이라고 불리겠어?","JPN":"主の狂犬って呼ばれるだけはあるわ。","ENG":"Why else would they be called the \\"Mad Dogs of the Lord\\"?","TWN":"人家不都稱呼他們為天主的走狗嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"Th-that's...","TWN":"那…那是……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"아까도 말했지만, 다 죽어가는 꼬마 하나 구하려다가 우리까지 휘말리는 건 사절이야.","JPN":"さっきも言ったけど、死にかけてる子どもを助けようとして私たちまで巻き込まれるのはお断りよ。","ENG":"Like I said before, I'm not willing to risk our lives to save some kid who's already half-dead.","TWN":"我剛也說過，我不會為了救一個快死的小鬼，而讓我們身陷危險。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"뭣보다 사교도들 사이에서 태어난 애잖아. 침식체를 숭배했던 자들의 아이라고?","JPN":"何より邪教徒の間で生まれた子でしょう？　侵食体を崇拝していた者たちの子どもなのよ？","ENG":"Plus, she's the child of a cultist! They worshipped C.O.s, no?","TWN":"更何況，她是邪教徒的孩子，他們是崇拜侵蝕體的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"옳으신 말씀이에요. 성황청은 우상의 숭배를 엄격히 금하니까요.","JPN":"ごもっともですわ。聖皇庁は偶像崇拝を厳格に禁じていますから。","ENG":"You're right. Idol worship is strictly prohibited by the Holy Curia.","TWN":"你說的沒錯，聖皇廳嚴格禁止偶像崇拜。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"하지만 그것이 죄인지도 모르는 어린 아이에게 죽음은 너무 가혹한 벌일지도 몰라요.","JPN":"でも、それが罪とも知らない子どもに、死は過酷すぎる罰ではないでしょうか。","ENG":"However, death may be too harsh a punishment for a child who was unaware of the sin.","TWN":"但她還那麼小，所謂不知者無罪，用死來懲罰她不會太殘忍嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"누구든 살아만 있다면, 그리고 속죄한다면……","JPN":"誰でも生きてさえいれば、そして贖罪すれば……","ENG":"If a person is still alive and makes atonement...","TWN":"無論是誰，只要活著認罪的話……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자비로우신 주님께서 용서해주실 거예요.","JPN":"慈悲深い主はお許しになるはずですわ。","ENG":"The merciful Lord will forgive her.","TWN":"慈愛的天主都會饒恕他的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"여기까지 안내해주셨는데 죄송합니다. 자매님.","JPN":"ここまで案内してくださったのに申し訳ありません。","ENG":"Sister Agnes, while I appreciate your assistance, I'm sorry.","TWN":"你帶我逃到這裡來，但很抱歉，姊妹。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"왔던 길을 되짚어가면 저 혼자서도 찾아갈 수 있을 거예요.","JPN":"来た道を辿って行けば私一人でもたどり着けるはずです。","ENG":"I'll be able to make it back by myself if I go back the way I came.","TWN":"我現在折回去的話，應該可以找到路。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"하아~ 곤란하네.","JPN":"はあ～困ったわね。","ENG":"*Sigh...* This isn't good...","TWN":"哀～真傷腦筋。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"자매님이 그런 표정을 짓고 있으면 신앙인으로서 마음이 약해지잖아.","JPN":"あなたがそんな顔をしてると、信仰者として決意が揺らぐじゃない。","ENG":"As a person of faith, my heart weakens when you look at me with those puppy dog eyes.","TWN":"看到你那副表情，身為一個有信仰的人，怎麼可能不心軟呢？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"좋아, 뭐 어떻게든 되겠지.","JPN":"いいわ。まあ、どうとでもなるでしょう。","ENG":"But, okay. It'll all work out in the end.","TWN":"好吧，船到橋頭自然直！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네? 그 말씀은……?","JPN":"はい？　それはつまり……？","ENG":"Huh? That means...?","TWN":"嗯？你的意思是……？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"도와줄게. 혼자 가는 것보단 둘이 가는 게 낫잖아?","JPN":"助けてあげるわ。一人で行くよりは二人の方がマシでしょう？","ENG":"I'll help you. Two is better than one, right?","TWN":"我幫你吧！二個人總比一個人好吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"대신 성무가 끝나면 같이 시원한 맥주 한 잔 정도는…….","JPN":"その代わりに、聖務が終わったら一緒に冷たいビール一杯くらいは……","ENG":"In exchange, how about you treat me with a cold beer aft─","TWN":"不過等聖務結束後，要一起去喝杯冰涼的啤酒……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"으, 으윽……!","JPN":"う、ううっ……！","ENG":"N-ngh...!","TWN":"唔，呃……！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아, 아그네스 자매님!!","JPN":"あ、シスター・アグネス！！","ENG":"S-sister Agnes!!","TWN":"艾…艾格妮絲姊妹！！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_HATE"},"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"OCTOPUS3_VATICAN_NULL_NULL","text":{"KOREA":"<color=#ff3636>성찬</color>을 준비하<color=#ff3636>라. 새로운 날</color>이 당도하<b>리</b>니.","JPN":"<color=#ff3636>聖餐</color>を用意し<color=#ff3636>ろ。新しい日</color>が到来<b>す</b>る。","ENG":"Prepare <color=#ff3636>the fea</color>st. A new da<color=#ff3636>wn is</color> com<b>in</b>g.\xA0","TWN":"預備<color=#ff3636>盛宴</color><color=#ff3636>吧。新天</color>已來<b>到</b>。\xA0"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"이, 이건 낮에 봤던 침식체!?","JPN":"こ、これは昼間遭遇した侵食体！？","ENG":"A-are those the C.O.s from earlier?!","TWN":"這…這是白天看到的侵蝕體！？"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"넬슨! 어서 도망쳐!","JPN":"ネルソン！　早く逃げなさい！","ENG":"Nelson! Run!","TWN":"尼爾森！快逃！"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L28_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"녀석들은…… 내가 막을테니까!","JPN":"やつらは……私が食い止めるから！","ENG":"I'll... block them off here!","TWN":"他們……就交給我！"},"stage":{"bg":"UNDER","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……시스터 넬슨.","JPN":"……シスターネルソン。","ENG":"Sister Nelson...","TWN":"……尼爾森姊妹。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신은 너무나 선량한 마음씨를 가졌군요.","JPN":"あなたはとても優しい心の持ち主ですね。","ENG":"You are far too naive.","TWN":"你有一顆非常善良的心。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"원시 종교 중에 흔한 사례가 있습니다. 부족의 주술사가 달군 돌 위를 걷는 의식이죠.","JPN":"原始宗教にはよくある事例です。部族の呪術師が熱い石の上を歩く儀式ですが。","ENG":"Primitive religions have a common ritual in which the tribe's shaman walks on burning hot stones.","TWN":"傳統宗教常聽說這種事，譬如某個部落的巫師踩在燒紅石頭上的儀式。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주술사는 마을의 미래를 예언하고 부족민의 안전을 기원하기 위해 무아지경으로 시뻘겋게 달아오른 돌 위를 밟아 나갑니다.","JPN":"呪術師は村の未来を予言し、部族民の安全を祈って無我夢中で真っ赤になった石の上を歩きます。","ENG":"The shaman walks across the heated stones, predicting the village's future and the safety of all the villagers.","TWN":"巫師因為要預言村莊的未來，替村民祈求平安，於是走上燒紅的石頭路上。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그걸 보는 마을 주민들은 초자연적이고 숭고한 모습에 도취되죠.","JPN":"それを見る村人は超自然的で崇高な姿に見惚れてしまします。","ENG":"The villagers who witness the supernatural and grandiose act are enchanted by it.","TWN":"看到這一幕的村民，就會被這超自然的現象，和巫師慷慨赴義的表情所吸引。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 그거 아십니까?","JPN":"ですが、ご存じですか？","ENG":"But did you know?","TWN":"但你知道嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그곳에서 한 발짝 떨어져서 객관적인 위치에서 그 광경을 보게 된다면…….","JPN":"そこから一歩下がって客観的な位置からその光景を見ると……","ENG":"If you take a step back and observe their acts objectively...","TWN":"若你稍微退一步，以客觀的角度來看這件事……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그건, 결국 삼류 마술사의 어설픈 트릭에 불과해요.","JPN":"それは、結局三流手品師のお粗末なトリックに過ぎません。","ENG":"You discover that all their so-called magic is nothing more than cheap tricks.","TWN":"那不過就是三流魔術師的伎倆。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"무슨 말씀을…… 하고 싶으신 건가요?","JPN":"おっしゃる意味が……よくわかりませんが？","ENG":"What... is it you want to say to me?","TWN":"請問……你到底想說什麼呢？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"<color=#ffd34c>의심할 수 없을 때까지 의심해라</color>.","JPN":"<color=#ffd34c>疑えなくなるまで疑え</color>。","ENG":"<color=#ffd34c>Doubt until thou cannot doubt any more</color>.","TWN":"<color=#ffd34c>凡事都要抱持懷疑的態度。</color>"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"심의회의 마음가짐이자, 요한 추기경님의 가르침이죠.","JPN":"審議会の心がけであり、ヨハン枢機卿の教えです。","ENG":"This is the motto of the Investigation Council, and also Cardinal Johan's teaching.","TWN":"這是議會的態度，也是約翰樞機主教的教導。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"이 분은……?","JPN":"この方は……？","ENG":"And this is...?","TWN":"這位是……？"},"stage":{"bg":"CHURCH","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 프란체스카. 그 마을에 파견되었던 <color=#ffd34c>진짜</color> 파견 수녀님이시죠.","JPN":"シスターフランチェスカ。あの村に派遣された<color=#ffd34c>本物</color>の派遣シスターです。","ENG":"Sister Francesca. She is the <color=#ffd34c>real</color> ally who was deployed to the village.","TWN":"法蘭西絲卡修女，她是<color=#ffd34c>真正</color>被派遣到村莊的修女。"},"stage":{"bg":"CHURCH","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그리고 현재 행방이 묘연합니다.","JPN":"そして現在は行方不明です。","ENG":"Also, her current whereabouts are unknown.","TWN":"但她現在下落不明。"},"stage":{"bg":"CHURCH","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"설마 그 말씀은…….","JPN":"まさか、それって……","ENG":"You mean to say...","TWN":"你的意思是……"},"stage":{"bg":"CHURCH","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼, 다시금 묻겠습니다. 시스터 넬슨.","JPN":"それでは、もう一度お聞きします。シスターネルソン。","ENG":"I shall ask you again, Sister Nelson.","TWN":"我再問你一次，尼爾森姊妹，"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신이 목격했던…… 그 여자는 누구입니까?","JPN":"あなたが目撃した……その女は誰ですか？","ENG":"The person you saw... Who was she?","TWN":"你看到的那個女生……是誰？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};